function Main() {
  const navigate = useNavigate();
  const [logoVisible, setLogoVisible] = useState(false);
  const [hintVisible, setHintVisible] = useState(false);
  const [fading, setFading] = useState(false);
  const [ripples, setRipples] = useState([]);

  useEffect(() => {
    const t1 = setTimeout(() => setLogoVisible(true), 300);
    const t2 = setTimeout(() => setHintVisible(true), 1800);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, []);

  const handleClick = (e) => {
    if (fading) return;
    const id = Date.now();
    const size = Math.max(window.innerWidth, window.innerHeight) * 2;
    setRipples([{ id, x: e.clientX - size / 2, y: e.clientY - size / 2, size }]);
    setFading(true);
    setTimeout(() => navigate("/login"), 700);
  };

  return (
    <>
      <style>{`
        @keyframes otgRipple {
          from { transform: scale(0); opacity: 1; }
          to   { transform: scale(6); opacity: 0; }
        }
      `}</style>

      {/* 클릭 후 화면을 덮는 오버레이: 평소엔 opacity:0(투명), 클릭 후 opacity:1(불투명)으로 전환 */}
      <div
        style={{
          position: "fixed",
          inset: 0,
          backgroundColor: "#F5F0EB",
          opacity: fading ? 1 : 0,
          transition: fading ? "opacity 0.6s ease" : "none",
          pointerEvents: "none",
          zIndex: 20,
        }}
      />

      {/* 리플 이펙트 레이어 */}
      <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 10, overflow: "hidden" }}>
        {ripples.map((r) => (
          <div
            key={r.id}
            style={{
              position: "absolute",
              width: r.size,
              height: r.size,
              left: r.x,
              top: r.y,
              borderRadius: "50%",
              backgroundColor: "rgba(30,25,20,0.07)",
              animation: "otgRipple 0.7s ease-out forwards",
            }}
          />
        ))}
      </div>

      {/* 메인 화면 */}
      <div
        onClick={handleClick}
        style={{
          width: "100vw",
          height: "100vh",
          backgroundColor: "#F5F0EB",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          cursor: "pointer",
          overflow: "hidden",
          position: "relative",
          userSelect: "none",
        }}
      >
        {/* 로고: 위에서 아래로 떨어지는 애니메이션 */}
        <div
          style={{
            opacity: logoVisible ? 1 : 0,
            transform: logoVisible ? "translateY(0)" : "translateY(-60px)",
            transition: "opacity 1.2s cubic-bezier(0.22,1,0.36,1), transform 1.2s cubic-bezier(0.22,1,0.36,1)",
          }}
        >
          <svg
            viewBox="0 0 1774 887"
            xmlns="http://www.w3.org/2000/svg"
            style={{ width: "min(480px, 72vw)", height: "auto", display: "block" }}
          >
            <g transform="translate(0,887) scale(0.1,-0.1)" fill="#1e1914" stroke="none">
              {OTG_LOGO_PATHS.map((d, i) => (
                <path key={i} d={d} />
              ))}
            </g>
          </svg>
        </div>

        {/* 힌트 텍스트 */}
        <p
          style={{
            position: "absolute",
            bottom: 52,
            left: "50%",
            transform: "translateX(-50%)",
            fontSize: 12,
            letterSpacing: "0.18em",
            color: "#9a9187",
            textTransform: "uppercase",
            fontFamily: "Georgia, serif",
            opacity: hintVisible ? 1 : 0,
            transition: "opacity 1s ease",
            whiteSpace: "nowrap",
            margin: 0,
          }}
        >
          click to enter
        </p>
      </div>
    </>
  );
}

export default Main;